import{_ as t,o,c as n,au as a}from"./chunks/framework.Bpqx6pAq.js";const p=JSON.parse('{"title":"Content","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/utilities/utils.content.md","filePath":"api/core/utilities/utils.content.md"}'),r={name:"api/core/utilities/utils.content.md"};function i(c,e,d,l,s,m){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <code>utils.content.js</code> module provides the content binding and filtering engine used throughout KDK to connect configuration-driven UI component definitions to their runtime context. It enables declarative handler and property binding using <code>:xxx</code> syntax in configuration objects.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="filtercontent-content-filter" tabindex="-1"><code>filterContent(content, filter)</code> <a class="header-anchor" href="#filtercontent-content-filter" aria-label="Permalink to &quot;`filterContent(content, filter)`&quot;">​</a></h3><p>Recursively applies a <a href="https://github.com/crcn/sift.js" target="_blank" rel="noreferrer">sift</a> filter to a content definition. Supports both flat arrays and mode-keyed objects.</p><ul><li><strong>Parameters:</strong><ul><li><code>content</code> <em>(Array | Object | any)</em>: The content to filter. Arrays are filtered directly; objects with a <code>content</code> sub-key recurse; objects with mode keys filter each mode.</li><li><code>filter</code> <em>(Object)</em>: A sift-compatible filter object.</li></ul></li><li><strong>Returns:</strong> The filtered content (same type as input).</li></ul><h3 id="bindcontent-content-context-omit" tabindex="-1"><code>bindContent(content, context, omit?)</code> <a class="header-anchor" href="#bindcontent-content-context-omit" aria-label="Permalink to &quot;`bindContent(content, context, omit?)`&quot;">​</a></h3><p>Binds all handler functions and <code>:xxx</code> properties in a content definition array to the given context object. Mutates the content in place.</p><ul><li><strong>Parameters:</strong><ul><li><code>content</code> <em>(Array)</em>: Array of component definition objects.</li><li><code>context</code> <em>(Object)</em>: The binding context (typically a Vue component instance).</li><li><code>omit</code> <em>(Array, default <code>[]</code>)</em>: Property keys to skip during binding (e.g. <code>[&#39;header&#39;, &#39;fab&#39;]</code>).</li></ul></li><li><strong>Returns:</strong> The mutated <code>content</code> array.</li></ul><h3 id="bindproperties-item-context-omit" tabindex="-1"><code>bindProperties(item, context, omit?)</code> <a class="header-anchor" href="#bindproperties-item-context-omit" aria-label="Permalink to &quot;`bindProperties(item, context, omit?)`&quot;">​</a></h3><p>Recursively walks an object or array and replaces any string value starting with <code>:</code> with the corresponding value from <code>context</code>.</p><ul><li><strong>Parameters:</strong><ul><li><code>item</code> <em>(Object | Array | any)</em>: The item to process.</li><li><code>context</code> <em>(Object)</em>: The binding context.</li><li><code>omit</code> <em>(Array, default <code>[]</code>)</em>: Keys to skip.</li></ul></li><li><strong>Returns:</strong> The mutated item.</li></ul><h3 id="bindhandler-component-path-context" tabindex="-1"><code>bindHandler(component, path, context)</code> <a class="header-anchor" href="#bindhandler-component-path-context" aria-label="Permalink to &quot;`bindHandler(component, path, context)`&quot;">​</a></h3><p>Resolves the handler at <code>path</code> on a component and replaces it with a bound function. Supports three forms:</p><ul><li><p><strong>Array</strong>: each element is bound and the final handler returns <code>true</code> only if all handlers return <code>true</code> (AND semantics).</p></li><li><p><strong>Object <code>{ name, params }</code></strong>: binds <code>context[name]</code> with optional params. Names starting with <code>:</code> are treated as property bindings.</p></li><li><p><strong>String</strong>: binds <code>context[name]</code>. A leading <code>!</code> negates the result.</p></li><li><p><strong>Parameters:</strong></p><ul><li><code>component</code> <em>(Object)</em>: The component definition.</li><li><code>path</code> <em>(string)</em>: Lodash path to the handler within <code>component</code>.</li><li><code>context</code> <em>(Object)</em>: The binding context.</li></ul></li><li><p><strong>Returns:</strong> The resolved handler function.</p></li></ul><h3 id="generatehandler-context-name-params" tabindex="-1"><code>generateHandler(context, name, params?)</code> <a class="header-anchor" href="#generatehandler-context-name-params" aria-label="Permalink to &quot;`generateHandler(context, name, params?)`&quot;">​</a></h3><p>Creates a closure that calls <code>context[name]</code> with optional bound parameters when invoked.</p><ul><li><strong>Parameters:</strong><ul><li><code>context</code> <em>(Object)</em>: The binding context.</li><li><code>name</code> <em>(string)</em>: Function or property name on context. Prefix with <code>!</code> to negate.</li><li><code>params</code> <em>(any, optional)</em>: Static or bound parameters passed to the function.</li></ul></li><li><strong>Returns:</strong> <code>Function</code> — the generated handler.</li></ul><h3 id="bindparams-params-context-args" tabindex="-1"><code>bindParams(params, context, args)</code> <a class="header-anchor" href="#bindparams-params-context-args" aria-label="Permalink to &quot;`bindParams(params, context, args)`&quot;">​</a></h3><p>Recursively resolves bound parameter values, handling arrays, objects, and scalar <code>:xxx</code> strings.</p><ul><li><strong>Parameters:</strong><ul><li><code>params</code> <em>(any)</em>: Parameters to resolve.</li><li><code>context</code> <em>(Object)</em>: The binding context.</li><li><code>args</code> <em>(Array)</em>: The original handler arguments (for <code>:n</code> index references).</li></ul></li><li><strong>Returns:</strong> The resolved parameters.</li></ul><h3 id="getboundvalue-value-context-args" tabindex="-1"><code>getBoundValue(value, context, args?)</code> <a class="header-anchor" href="#getboundvalue-value-context-args" aria-label="Permalink to &quot;`getBoundValue(value, context, args?)`&quot;">​</a></h3><p>Resolves a single <code>:xxx</code> binding expression:</p><ul><li><p><code>:store.path</code> — reads from the global <code>Store</code> by path.</p></li><li><p><code>:storeRef.path</code> — returns a reactive <code>ref</code> from the global <code>Store</code>.</p></li><li><p><code>:n</code> — returns the nth element of <code>args</code> (handler call arguments).</p></li><li><p><code>:prop</code> — reads <code>context[prop]</code>.</p></li><li><p>Non-<code>:</code> strings are returned as-is.</p></li><li><p><strong>Parameters:</strong></p><ul><li><code>value</code> <em>(any)</em>: The value to resolve.</li><li><code>context</code> <em>(Object)</em>: The binding context.</li><li><code>args</code> <em>(Array, optional)</em>: Handler call arguments.</li></ul></li><li><p><strong>Returns:</strong> The resolved value, or <code>undefined</code> if the binding target is not found.</p></li></ul>',25)])])}const h=t(r,[["render",i]]);export{p as __pageData,h as default};
